import ldap3

def search_user_by_username(ldap_server, base_dn, username, admin_dn, admin_password):
    # Connect to the LDAP server
    server = ldap3.Server(ldap_server)
    conn = ldap3.Connection(server, admin_dn, admin_password, auto_bind=True)

    # Define the search filter and attributes
    search_filter = f"(uid={username})"
    search_attributes = ['cn', 'mail']

    # Perform the search
    conn.search(base_dn, search_filter, attributes=search_attributes)

    # Process the results
    if len(conn.entries) > 0:
        for entry in conn.entries:
            print(f"Common Name: {entry.cn}")
            print(f"Email: {entry.mail}")
    else:
        print("No user found with the given username.")

    # Unbind the connection
    conn.unbind()

# Example usage
search_user_by_username('ldap.example.com', 'dc=example,dc=com', 'johndoe', 'cn=admin,dc=example,dc=com', 'admin_password')